<?php $tituloPagina="Agências"; require_once "includes/header.php"; $pdo=getDB(); if($_SERVER["REQUEST_METHOD"]==="POST"){$a=$_POST["acao"]??"";if($a==="novo")$pdo->prepare("INSERT INTO agencias(empresa,nome,email,telefone,contato,cidade,estado)VALUES(?,?,?,?,?,?,?)")->execute([$_POST["empresa"],$_POST["nome"],$_POST["email"]??"",$_POST["telefone"]??"",$_POST["contato"]??"",$_POST["cidade"]??"",$_POST["estado"]??""]);elseif($a==="excluir")$pdo->prepare("DELETE FROM agencias WHERE id=?")->execute([(int)$_POST["id"]]);header("Location:/agencias.php");exit;} $rows=$pdo->query("SELECT * FROM agencias ORDER BY nome")->fetchAll(); ?><div class="breadcrumb-bar"><a href="/index.php"><i class="bi bi-house-fill"></i></a>/Agências</div><div class="d-flex justify-content-between mb-3"><h2>Gerenciar agências</h2><button class="btn btn-info btn-sm text-white" data-bs-toggle="modal" data-bs-target="#mA">Novo</button></div><div class="table-responsive"><table class="table table-bordered table-listagem"><thead><tr><th>EMPRESA</th><th>NOME</th><th>CONTATO</th><th>OPÇÕES</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=$r["empresa"]?></td><td><?=htmlspecialchars($r["nome"])?></td><td style="font-size:12px"><?=htmlspecialchars($r["telefone"]??"")?><br><?=htmlspecialchars($r["cidade"]??"")?></td><td class="text-center"><form method="POST" class="d-inline" onsubmit="return confirm('Excluir?')"><input type="hidden" name="acao" value="excluir"><input type="hidden" name="id" value="<?=$r["id"]?>"><button class="btn btn-danger btn-sm"><i class="bi bi-trash"></i></button></form></td></tr><?php endforeach;?></tbody></table></div><div class="modal fade" id="mA" tabindex="-1"><div class="modal-dialog"><div class="modal-content"><div class="modal-header bg-danger text-white"><h5>Nova agência</h5><button type="button" class="btn-close btn-close-white" data-bs-dismiss="modal"></button></div><form method="POST"><input type="hidden" name="acao" value="novo"><div class="modal-body"><div class="row g-2"><div class="col-4"><label>Empresa</label><select name="empresa" class="form-select"><option>RS E SC</option><option>RS</option><option>SC</option></select></div><div class="col-8"><label>Nome</label><input type="text" name="nome" class="form-control" required></div><div class="col-6"><label>Telefone</label><input type="text" name="telefone" class="form-control"></div><div class="col-6"><label>E-mail</label><input type="email" name="email" class="form-control"></div><div class="col-6"><label>Contato</label><input type="text" name="contato" class="form-control"></div><div class="col-4"><label>Cidade</label><input type="text" name="cidade" class="form-control"></div><div class="col-2"><label>UF</label><input type="text" name="estado" class="form-control" maxlength="2"></div></div></div><div class="modal-footer"><button type="submit" class="btn btn-success">Salvar</button><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Fechar</button></div></form></div></div></div><?php require_once "includes/footer.php"; ?>